class FreqStack {
public:
    FreqStack() {

    }

    void push(int val) {
        freq[val]++;
        if (freqs.count(freq[val])) {
            freqs[freq[val]].push_back(val);
        } else {
            freqs[freq[val]] = vector<int>{val};
        }
    }

    int pop() {
        int maxFreq = 0, res;
        for (auto it = freqs.rbegin(); it != freqs.rend(); ++it) {
            if (it->second.size() > maxFreq) {
                maxFreq = it->second.size();
                res = it->second.back();
                it->second.pop_back();
            }
        }
        freq[res]--;
        return res;
    }
private:
    unordered_map<int, int> freq;
    unordered_map<int, vector<int>> freqs;
};
```
